const https = require("https");
const http  = require("http");
const fs    = require("fs");
const path  = require("path");
const url   = require("url");

const PORT       = process.env.PORT || 3000;
const OPENAI_KEY = process.env.OPENAI_API_KEY || "";
const IMG_B64    = "";

function buildPrompt(ev) {
  var name    = (ev.name    || "").trim();
  var prefix  = (ev.prefix  || "").trim();
  var genre   = (ev.genre   || "").trim();
  var day     = (ev.day     || "").trim();
  var date    = (ev.date    || "").trim();
  var dj      = (ev.dj      || "").trim();
  var contact = (ev.contact || "").trim();
  var time    = (ev.time    || "").trim();
  var entry   = (ev.entry   || "").trim();

  var djList = dj.length ? dj.split(",").map(function(d){return d.trim();}).filter(Boolean) : [];

  // Build the new text inventory
  var newTexts = [];
  if (prefix)  newTexts.push("Prefix/subtitle above title: \"" + prefix + "\"");
  if (name)    newTexts.push("Main event title: \"" + name + "\"");
  if (genre)   newTexts.push("Edition/banner text: \"" + genre + "\"");
  if (day)     newTexts.push("Day of week: \"" + day.toUpperCase() + "\"");
  if (date)    newTexts.push("Date: \"" + date + "\"");
  if (djList.length) newTexts.push("DJ/act names (one per line): " + djList.map(function(d){return "\""+d+"\"";}).join(", "));
  if (contact) newTexts.push("Website/contact: \"" + contact + "\"");
  if (time)    newTexts.push("Entry time: \"Einlass: " + time + " Uhr\"");
  if (entry)   newTexts.push("Entry price: \"Eintritt: " + entry + "\"");

  return "I need you to edit this nightclub event flyer by replacing its text content.\n\n" +
    "RULES:\n" +
    "1. Keep the image EXACTLY the same: same composition, same people, same colors, same layout, same effects, same font styles\n" +
    "2. Find ALL text elements in the flyer\n" +
    "3. Replace them with the NEW TEXT LIST below\n" +
    "4. Any text element that has NO replacement in the list: REMOVE IT COMPLETELY (erase it, make it invisible)\n" +
    "5. Do not invent or add any text that is not in the list\n\n" +
    "NEW TEXT LIST (use only these):\n" +
    newTexts.map(function(t,i){return (i+1)+". "+t;}).join("\n") + "\n\n" +
    "Place each text element in the same position and with the same font style as the original corresponding element. " +
    "Any original text not covered by this list must be erased.";
}

var server = http.createServer(function(req, res) {
  var p = url.parse(req.url).pathname;
  res.setHeader("Access-Control-Allow-Origin","*");
  res.setHeader("Access-Control-Allow-Headers","Content-Type");
  if (req.method === "OPTIONS") { res.writeHead(200); res.end(); return; }

  if (req.method === "GET" && p === "/") {
    fs.readFile(path.join(__dirname,"public","index.html"), function(err, data) {
      if (err) { res.writeHead(404); res.end("Not found"); return; }
      res.setHeader("Content-Type","text/html");
      res.writeHead(200); res.end(data);
    });
    return;
  }

  if (req.method === "POST" && p === "/api/generate") {
    if (!OPENAI_KEY) { res.writeHead(500); res.end(JSON.stringify({error:"OPENAI_API_KEY not set"})); return; }
    var body = "";
    req.on("data", function(c){ body += c; });
    req.on("end", function() {
      var ev;
      try { ev = JSON.parse(body); } catch(e) { res.writeHead(400); res.end(JSON.stringify({error:"Invalid JSON"})); return; }

      var prompt = buildPrompt(ev);
      console.log("PROMPT:\n" + prompt);

      var payload = JSON.stringify({
        model: "gpt-4o",
        input: [{
          role: "user",
          content: [
            { type: "input_image", image_url: "data:image/jpeg;base64," + IMG_B64 },
            { type: "input_text",  text: prompt }
          ]
        }],
        tools: [{
          type: "image_generation",
          quality: "high",
          size: "1024x1536",
          moderation: "low"
        }]
      });

      var apiReq = https.request({
        hostname: "api.openai.com",
        path: "/v1/responses",
        method: "POST",
        headers: {
          "Authorization":  "Bearer "+OPENAI_KEY,
          "Content-Type":   "application/json",
          "Content-Length": Buffer.byteLength(payload)
        }
      }, function(apiRes) {
        var data = "";
        apiRes.on("data", function(c){ data += c; });
        apiRes.on("end", function() {
          console.log("Status:", apiRes.statusCode, data.substring(0,300));
          try {
            var j = JSON.parse(data);
            if (apiRes.statusCode !== 200) {
              return res.writeHead(apiRes.statusCode), res.end(JSON.stringify({error: j.error&&j.error.message||data.substring(0,300)}));
            }
            var imgB64 = null;
            (j.output||[]).forEach(function(item){
              if(item.type==="image_generation_call") imgB64=item.result;
              (item.content||[]).forEach(function(c){
                if(c.type==="image_generation_call") imgB64=c.result;
              });
            });
            if(!imgB64) return res.writeHead(500), res.end(JSON.stringify({error:"No image: "+data.substring(0,300)}));
            res.setHeader("Content-Type","application/json");
            res.writeHead(200);
            res.end(JSON.stringify({url:"data:image/png;base64,"+imgB64}));
          } catch(e) {
            res.writeHead(500); res.end(JSON.stringify({error:"Parse error: "+data.substring(0,200)}));
          }
        });
      });
      apiReq.on("error", function(e){ res.writeHead(500); res.end(JSON.stringify({error:e.message})); });
      apiReq.write(payload);
      apiReq.end();
    });
    return;
  }
  res.writeHead(404); res.end("Not found");
});
server.timeout = 180000;
server.listen(PORT, function(){ console.log("NightKit on port "+PORT); });
